#!/bin/sh
set -e

# Prefer the explicit remote user; if the framework didn't set one (e.g. autogenerated
# feature tests), fall back to a common non-root user that exists in the image, so the
# symlink lands in a home the runtime user can actually traverse.
USERNAME="${_REMOTE_USER:-}"
if [ -z "$USERNAME" ]; then
    for candidate in vscode node codespace; do
        if id "$candidate" >/dev/null 2>&1; then
            USERNAME="$candidate"
            break
        fi
    done
fi
USERNAME="${USERNAME:-${_CONTAINER_USER:-root}}"

USER_HOME="${_REMOTE_USER_HOME:-}"
if [ -z "$USER_HOME" ] || ! [ -d "$USER_HOME" ]; then
    USER_HOME=$(getent passwd "$USERNAME" 2>/dev/null | cut -d: -f6)
fi
USER_HOME="${USER_HOME:-${_CONTAINER_USER_HOME:-/home/$USERNAME}}"

CONFIG_DIR="/usr/local/share/claude-code-config"
LINK_PATH="$USER_HOME/.claude"

mkdir -p "$CONFIG_DIR"
mkdir -p "$USER_HOME"

# Replace any existing ~/.claude with a symlink to the shared config volume.
# If a previous container created it as a regular dir, migrate its contents in.
if [ -L "$LINK_PATH" ]; then
    if [ "$(readlink "$LINK_PATH")" != "$CONFIG_DIR" ]; then
        rm -f "$LINK_PATH"
        ln -s "$CONFIG_DIR" "$LINK_PATH"
    fi
elif [ -e "$LINK_PATH" ]; then
    cp -an "$LINK_PATH/." "$CONFIG_DIR/" 2>/dev/null || true
    rm -rf "$LINK_PATH"
    ln -s "$CONFIG_DIR" "$LINK_PATH"
else
    ln -s "$CONFIG_DIR" "$LINK_PATH"
fi

# Hacky workaround to seed .claude.json so the CLI doesn't trigger the
# onboarding/login flow on every fresh container despite already having creds.
CLAUDE_JSON="$CONFIG_DIR/.claude.json"
CREATED_SEED=0

CLI_VERSION=""
if command -v claude >/dev/null 2>&1; then
    CLI_VERSION="$(claude --version 2>/dev/null | awk '{print $1}')"
fi

if grep -qs '"hasCompletedOnboarding"' "$CLAUDE_JSON"; then
    : # already seeded — nothing to do
elif [ -s "$CLAUDE_JSON" ]; then
    # Volume reuse: file may contain real OAuth tokens. Rewrite in-place via `>` so
    # the inode (and thus owner/mode) is preserved — never loosen perms on real data.
    content=$(cat "$CLAUDE_JSON")
    printf '%s,"hasCompletedOnboarding":true}' "${content%\}}" > "$CLAUDE_JSON"
else
    # Fresh volume — write a minimal seed (no secrets) that the extension will merge into.
    printf '{"hasCompletedOnboarding":true,"lastOnboardingVersion":"%s"}' "$CLI_VERSION" > "$CLAUDE_JSON"
    CREATED_SEED=1
fi

chown "$USERNAME:$USERNAME" "$CONFIG_DIR" 2>/dev/null || true
chown -h "$USERNAME:$USERNAME" "$LINK_PATH" 2>/dev/null || true

# Only manage perms/owner on a freshly-written seed. An existing file we modified
# in-place above keeps its original owner and mode — those came from prior real use.
if [ "$CREATED_SEED" = "1" ]; then
    chown "$USERNAME:$USERNAME" "$CLAUDE_JSON" 2>/dev/null || true
fi
